import { useState } from "react";

export default function WeddingRSVPNight({}){
    const [dropdownWithNames, setShowDropDownWithNames] = useState("");
    const [name, setSelectedName] = useState("")
    const [answer, setAnswer] = useState("");
    const handleChange = (e) => {
        console.log(e)
        if (e.target.value === 'yesButOne'){
            setShowDropDownWithNames(true)

        }
        setAnswer(e.target.value);

    }

const handleSubmit = async () => {
  const API_URL = process.env.REACT_APP_API_URL;
  let rsvpArray = Object.values(guestChoices); // ✅ convert guestChoices object to array
  rsvpArray = rsvpArray.map(obj => ({
    ...obj,
    quizAnswer: airmiles,
    children: childrenAnswer
  }));

  try {
    const res = await fetch(`${API_URL}/api/rsvps/batch`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(rsvpArray),
    });

    if (res.ok) {
      const data = await res.json();
      setRSVPSubmittedSuccess(true)
      setDataResponses(res)
      const isAttending = rsvpArray.some(rsvp => rsvp.response === true);
      console.log(isAttending)
      if (isAttending) {
        navigate("/info");
      } else {
        navigate("/declined")
      }
    } else {
      setRSVPSubmittedSuccess(false)
    }
  } catch (err) {
    console.error(err);
    alert("Error submitting RSVP.");
  }
};
    return (
                  <>
        <div className={answer === 'yes' ? "option btn-active" : "option"}>
            <label htmlFor="yes">
                <input type="radio" id="yes" name="nightChoice" value="yes" onChange={handleChange} />
                Yes we would love too!
            </label>
        </div>
        <div className={answer === 'yesButOne' ? "option btn-active" : "option"}>
            <label htmlFor="yesButOne">
                <input type="radio" id="yesButOne" name="nightChoice" value="yesButOne" onChange={handleChange} />
                Yes but only one of us can make it
            </label>
        </div>
        <select
            value={selectedName}
        >
        <option value="">Select a name</option>

            {props?.names.map((name) => (
            <option key={name} value={name}>
                {name}
            </option>
            ))}
        </select>
        <div className={answer === 'no' ? "option btn-active" : "option"}>
                <label htmlFor="no">
                    <input type="radio" id="no" name="nightChoice" value="no" onChange={handleChange} />
                    Sorry we cannot make it 
                </label>
        </div>
            
            {answer !== '' && (
            <div className="option btn-active" onClick={handleSubmit}>
                 Submit RSVP
            </div>              
            )}
            
            </>
    )
}
